var uploader={plupload:undefined,params:undefined,count:0,max_count:0,postId:"",init:function(a){uploader.params=a;uploader.plupload=new plupload.Uploader({runtimes:"html5,html4",browse_button:uploader.params.button,container:uploader.params.container,max_file_size:uploader.params.max_file_size+"mb",url:uploader.params.url,flash_swf_url:"/scripts/plupload/Moxie.swf",filters:[{title:"Image files",extensions:"jpg,jpeg,gif,png"}],multipart_params:{action:"upload",uuid:a.uuid}});uploader.plupload.init();if(uploader.count>=uploader.max_count){$("#"+uploader.params.button).hide()}uploader.plupload.bind("FilesAdded",function(b,c){b.refresh();b.start()});uploader.plupload.bind("BeforeUpload",function(b,c){$("#"+uploader.params.button).addClass("button_in_action");if(uploader.count>=uploader.max_count){$("#"+uploader.params.button).hide();b.stop();$("#"+uploader.params.button).removeClass("button_in_action")}});uploader.plupload.bind("FileUploaded",function(b,d,f){var c=f.response.replace(/^.*?\{/,"{").replace(/\}.*$/,"}");if(c.indexOf("Превышен лимит")>0){alert("Не удалось загрузить файл на сервер. Размер файла слишком большой.")}else{var e=JSON.parse(c);if(e.success){uploader.count++;if(uploader.count>=uploader.max_count){$("#"+uploader.params.button).hide();b.stop()}$("#"+uploader.params.container).append('<div class="uploader_file" id="'+e.key+'"><a href="'+e.url+'" target="_blank"><img src="'+e.url_preview+'" /></a><div class="uploader_close" title="Удалить" onclick="uploader.fileDelete(\''+e.key+"', '"+e.name+'\')"></div><input type="hidden" name="sort[]" value="'+e.name+'"></div>');$("#i_uploader_container_multi").sortable();$("#i_uploader_container_multi").disableSelection()}else{alert(e.error)}}$("#"+uploader.params.button).removeClass("button_in_action");b.refresh()})},fileDelete:function(b,a){$.ajax({url:uploader.params.url,type:"POST",mode:"abort",dataType:"json",data:{action:"delete",postId:uploader.postId,uuid:uploader.params.uuid,key:a},success:function(d){if(d.success){uploader.count--;$("#"+b).remove();var c=uploader.plupload.getFile(b);if(c){uploader.plupload.removeFile(c)}if(uploader.count<uploader.max_count){$("#"+uploader.params.button).show()}uploader.plupload.refresh()}},failed:function(){alert("Не удалось удалить файл. Попробуйте позднее")}})}};